var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS006M0073-02: <color=#ffd34c>【기록-006】 검토 회의</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>……\\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>……\\nCCN No. FS006M0073-02：<color=#ffd34c>【記録-006】検討会議</color>","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS006M0073-02: <color=#ffd34c>【Record-006】 Review Conference</color>","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS007M0000-02: <color=#ffd34c>【記錄-006】 討論會議</color>","THA":"กระบวนการตรวจสอบประวัติเพื่อความปลอดภัย AEGIS 8 PBLIT: <color=#ffd34c>เปิดทำงาน</color>     \\nADC แฟกเตอร์: <color=#ffd34c>ยืนยันในระดับอัลฟ่า</color>     \\nCCN หมายเลข FS006M0073-02: <color=#ffd34c>[บันทึก-006] การประชุมทบทวน</color>","VTN":"TRÌNH TỰ AN NINH AEGIS 8 PBLIT: <color=#ffd34c>ĐÃ KÍCH HOẠT</color>     \\nTHÔNG SỐ ADC: <color=#ffd34c>XÁC NHẬN ALPHA </color>     \\nCCN Số FS006M0073-02: <color=#ffd34c>[Hồ Sơ-006] Hội Thảo Đánh Giá</color>","SCN":"AEGIS 8 PBLIT安全序列: <color=#ffd34c>激活</color>\\nADC 因素: <color=#ffd34c>阿尔法确认</color>     \\nCCN No. FS007M0000-02: <color=#ffd34c>【记录-006】 讨论会议</color>","DEU":"AEGIS 8 PBLIT-SICHERHEITSSEQUENZ: <color=#ffd34c>AKTIVIERT</color>     \\nADC-FAKTOR: <color=#ffd34c>ALPHA BESTÄTIGT</color>     \\nCCN-Nr. FS006M0073-02: <color=#ffd34c>【Aufzeichnung-006】 Überprüfungskonferenz</color>","FRA":"AEGIS 8 PROTOCOLE DE SÉCURITÉ PBLIT\xA0: <color=#ffd34c>ACTIVÉ</color>     \\nFACTEUR CAD\xA0: <color=#ffd34c>ALPHA CONFIRMÉ</color>     \\nCCN No. FS006M0073-02\xA0: <color=#ffd34c>【Rapport-006】 Conférence d'examen</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"흠.","JPN":"ふむ。","ENG":"Hmm.","TWN":"嗯。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그러고 보니 주시윤 군은 힐데 소대장이 데리고 왔다고 했었지?","JPN":"そういえば、アキヤマ・シリュウはヒルデ小隊長が連れてきたと言っていたな？","ENG":"So, Commander Hilde brought Joo Shiyoon?","TWN":"這麼說來，周時雲是被希爾德小隊長帶過來的？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그렇습니다.","JPN":"はい、そうです。","ENG":"Yes.","TWN":"是的。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"이전에 보고드린 대로 양친의 사망 직후 오갈 데 없는 주시윤 군을 스승님께서 제자로 삼은 것으로 알고 있습니다.","JPN":"以前に報告した通り両親の死後、引き取り手のなかったアキヤマ・シリュウを師匠が弟子としたそうです。","ENG":"As I previously reported, Master took him in as her apprentice because he had no place to go after his parents' death.","TWN":"就如之前的報告，父母去世後無處可去的周時雲君，被師父收為了弟子。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"어딘가 정상적인 고아원 같은 곳에나 맡기는 게 서로를 위해서 좋았을 것 같지만요.","JPN":"しかし、児童養護施設に預けた方がお互いにとってよかったのではないかと思いますが。","ENG":"Although it might have been better for both of them if he was sent to an orphanage.","TWN":"明明把他送到哪家孤兒院之類的地方，對我們大家都比較好。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......매정하구만.","JPN":"……冷たいな。","ENG":"That's cold.","TWN":"……真是無情呢。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"예전에는 좀 더...... 음...... 뭐랄까......","JPN":"昔はもう少し……、うん……何というか……","ENG":"You were more... um... sort of...","TWN":"你以前是更……嗯……怎麼說……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......그렇지, 감수성이 풍부한 성격이었던 것 같았는데.","JPN":"……感受性が豊かな性格だったと思うが。","ENG":"Yes, you were a lot more sensitive back in the days.","TWN":"……對，應該是個感受性更豐富的人啊。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......아드레날린 과다분비의 멍청이였다고 솔직하게 말씀하셔도 됩니다.","JPN":"……アドレナリン分泌過多のバカだったと、正直におっしゃってくださって大丈夫ですよ。","ENG":"You can be honest and say that I was an idiot who was always high on adrenaline.","TWN":"你直接說我是個腎上腺素分泌過多的笨蛋也沒關係。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......크흠! 크흠!","JPN":"……ゴホン！　ゴホン！","ENG":"Ahem! Ahem!","TWN":"……咳咳！咳咳！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그, 그 정도까지 생각한 건 아니네.","JPN":"そ、そんな風には思っていない。","ENG":"I-I wasn't thinking anything like that.","TWN":"我、我還沒想到那個程度。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그보다 주시윤 군의 양친에 대한 정보는 더 나온 게 있나?","JPN":"それより、アキヤマ・シリュウの両親に関する詳細情報はないのか？","ENG":"By the way, have you found anything more about Joo Shiyoon's parents?","TWN":"比起這個，有更多關於周時雲雙親的情報嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"회사로 데리고 온 건 그렇다 치고, 제자로까지 삼은 걸 보면 보통 관계는 아니었을 것 같은데......","JPN":"いくらなんでも、弟子として迎え入れたところを見ると、普通の関係ではなかったと思うのだが。","ENG":"I can understand Hilde bringing him here. But if she took him in as her apprentice, she must have had a close relationship with his parents...","TWN":"先不說把他帶到公司，連弟子都收了，看來關係並不一般……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"말씀드렸다시피 주시윤 군의 입사 전 정보에 대해서는 스승님께서 함구하시는 터라 별달리 말씀드릴 것이 없습니다.","JPN":"申し上げた通り、アキヤマ・シリュウの入社前の情報については、師匠が口を閉ざしているため他の記載はありません。","ENG":"As I told you before, Master is keeping any information regarding Joo Shiyoon's past a secret. I really don't have much to tell you.","TWN":"正如我所說，關於周時雲君入職前的情報，師父一直都是隻字不提，所以沒什麼特別能說的。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그야 물론 그렇겠지만, 자네가 누가 뭘 숨긴다고 순순히 알겠습니다...... 하고 가만히 있을 성격도 아니지 않나?","JPN":"しかし……、だからと言って君が彼の情報を詳細不明のままにしておくわけがないだろう？","ENG":"I understand, but you're not the type of person who would just back off from secrets.","TWN":"那是當然，但你明明是一旦知道人家隱瞞著什麼……不會就此善罷甘休的性格吧？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"분명히 끝내주는 협잡과 멋진 공갈, 상상도 못할 회유와 우아한 압박으로 사람들의 약점을 후벼 파서 뭔가 쓸만한 걸 알아냈을 테지.","JPN":"必ず巧妙なイカサマや脅し、想像を絶する懐柔と圧迫などで他人の弱点をえぐり、何か使える情報を手にしているはずだ。","ENG":"I'm sure you came up with some great ways to swindle, intimidate, appease, and pressure people to find something useful.","TWN":"你一定會用驚人的騙術、酷炫的恐嚇、無法想像的收買、優雅的壓迫，挖出了人們心中的弱點並挖出有沒有可用的東西。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"말해 보게.","JPN":"勿体ぶらずに教えるんだ。","ENG":"So, tell me.","TWN":"說吧。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};